import { IconCloud } from './icon-cloud.js'

function TechCloud() {
    const java = "data:image/svg+xml;base64,"

    const slugs = [
        "javascript",
        "html5",
        "react",
        "css",
        "C",
        "C++",
        "node.js",
        "vite",
    ]

    let images = slugs.map(
        (slug) => "https://cdn.simpleicons.org/" + slug + "/" + slug
    )
    images.push(java)

    return (
        <div>
            <IconCloud images={images}></IconCloud>
        </div>
    )
}

export default TechCloud;